import React from "react";
import NumberInput from "./NumberInput";

// Example: generic table model for rows in state
function ForecastTable({ rows, setRows }) {
  const handleChange = (index, field, value) => {
    const copy = [...rows];
    copy[index] = { ...copy[index], [field]: value };
    setRows(copy);
  };

  const addRow = () => {
    setRows([...rows, { product_id: 1, grade_pack_id: 1, forecast_qty: 0 }]);
  };

  const removeRow = (index) => {
    setRows(rows.filter((_, i) => i !== index));
  };

  return (
    <div>
      <button onClick={addRow}>Add Row</button>
      <table className="pp-table">
        <thead>
          <tr>
            <th>Product</th>
            <th>Grade/Pack</th>
            <th>Forecast Qty</th>
            <th />
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i}>
              <td>
                <input
                  value={r.product_id}
                  onChange={(e) => handleChange(i, "product_id", Number(e.target.value))}
                />
              </td>
              <td>
                <input
                  value={r.grade_pack_id}
                  onChange={(e) => handleChange(i, "grade_pack_id", Number(e.target.value))}
                />
              </td>
              <td>
                <input
                  value={r.forecast_qty}
                  onChange={(e) => handleChange(i, "forecast_qty", Number(e.target.value))}
                />
              </td>
              <td>
                <button onClick={() => removeRow(i)}>X</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default ForecastTable;
